from fastapi import APIRouter, Form, HTTPException, UploadFile
from fastapi import File as FastAPIFile

from app.api.deps import DBSession
from app.schemas.entry import EntryOut
from app.schemas.project import ProjectCreate, ProjectOut, ProjectUpdate
from app.services import entry_service, project_service

router = APIRouter(prefix="/projects")

BASE_AUDIO_URL = "http://localhost:2701/uploads"


def _entry_to_out(entry) -> EntryOut:
    audio_url = f"{BASE_AUDIO_URL}/{entry.audio_filename}" if entry.audio_filename else None
    return EntryOut(
        id=entry.id,
        project_id=entry.project_id,
        text_content=entry.text_content,
        audio_filename=entry.audio_filename,
        audio_url=audio_url,
        created_at=entry.created_at,
    )


@router.get("", response_model=list[ProjectOut])
def list_projects(db: DBSession):
    projects = project_service.get_all(db)
    result = []
    for p in projects:
        out = ProjectOut.model_validate(p)
        out.entry_count = len(p.entries)
        result.append(out)
    return result


@router.post("", response_model=ProjectOut, status_code=201)
def create_project(data: ProjectCreate, db: DBSession):
    project = project_service.create(db, data)
    out = ProjectOut.model_validate(project)
    out.entry_count = 0
    return out


@router.put("/{project_id}", response_model=ProjectOut)
def update_project(project_id: int, data: ProjectUpdate, db: DBSession):
    project = project_service.get_by_id(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    project = project_service.update(db, project, data)
    out = ProjectOut.model_validate(project)
    out.entry_count = len(project.entries)
    return out


@router.delete("/{project_id}", status_code=204)
def delete_project(project_id: int, db: DBSession):
    project = project_service.get_by_id(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    project_service.delete(db, project)


@router.get("/{project_id}/entries", response_model=list[EntryOut])
def list_entries(project_id: int, db: DBSession):
    project = project_service.get_by_id(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    entries = entry_service.get_by_project(db, project_id)
    return [_entry_to_out(e) for e in entries]


@router.post("/{project_id}/entries", response_model=EntryOut, status_code=201)
def create_entry(
    project_id: int,
    db: DBSession,
    text_content: str = Form(...),
    audio: UploadFile | None = FastAPIFile(None),
):
    project = project_service.get_by_id(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    entry = entry_service.create(db, project_id, text_content, audio)
    return _entry_to_out(entry)


@router.delete("/entries/{entry_id}", status_code=204)
def delete_entry(entry_id: int, db: DBSession):
    entry = entry_service.get_by_id(db, entry_id)
    if not entry:
        raise HTTPException(status_code=404, detail="Entry not found")
    entry_service.delete(db, entry)

