/* ============================================
   VoiceNote — Dark editorial aesthetic
   Fonts: Cormorant Garamond (display) + JetBrains Mono (body/code)
   ============================================ */

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font-display: 'Cormorant Garamond', 'Libre Baskerville', Georgia, serif;
  --font-mono: 'JetBrains Mono', 'Courier New', monospace;

  --bg:           #0f0e0c;
  --bg-sidebar:   #141210;
  --bg-surface:   #1a1814;
  --bg-raised:    #221f1a;
  --bg-hover:     #2a2620;

  --gold:         #c9a84c;
  --gold-dim:     #8c6e2a;
  --gold-glow:    rgba(201,168,76,0.15);
  --amber:        #e8a030;
  --text:         #e8e0d0;
  --text-muted:   #7a7060;
  --text-dim:     #4a4540;
  --border:       #2e2a24;
  --border-gold:  rgba(201,168,76,0.3);

  --red:          #c0392b;
  --green:        #4a9b6f;
  --error-bg:     rgba(192,57,43,0.12);

  --sidebar-w: 280px;
  --transition: 220ms ease;
}

html, body {
  height: 100%;
  width: 100%;
}

body {
  font-family: var(--font-mono);
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  display: flex;
  overflow: hidden;
}

/* ============================================
   LAYOUT: sidebar + main
   ============================================ */

.sidebar {
  width: var(--sidebar-w);
  min-width: var(--sidebar-w);
  background: var(--bg-sidebar);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  height: 100vh;
  position: relative;
  z-index: 10;
}

.main {
  flex: 1;
  height: 100vh;
  overflow-y: auto;
  position: relative;
}

/* ============================================
   SIDEBAR
   ============================================ */

.sidebar__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 16px;
  border-bottom: 1px solid var(--border);
}

.sidebar__logo {
  display: flex;
  align-items: center;
  gap: 10px;
}

.sidebar__logo-icon {
  font-size: 18px;
  color: var(--gold);
  line-height: 1;
}

.sidebar__logo-text {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 600;
  color: var(--text);
  letter-spacing: 0.02em;
}

.sidebar__search {
  padding: 14px 16px 10px;
}

.search-input {
  width: 100%;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: 4px;
  color: var(--text);
  font-family: var(--font-mono);
  font-size: 11px;
  padding: 8px 12px;
  outline: none;
  transition: border-color var(--transition);
}

.search-input::placeholder {
  color: var(--text-dim);
}

.search-input:focus {
  border-color: var(--gold-dim);
}

.sidebar__nav {
  flex: 1;
  overflow-y: auto;
  padding: 6px 0;
}

.sidebar__nav::-webkit-scrollbar {
  width: 4px;
}
.sidebar__nav::-webkit-scrollbar-track {
  background: transparent;
}
.sidebar__nav::-webkit-scrollbar-thumb {
  background: var(--bg-hover);
  border-radius: 2px;
}

.sidebar__loading {
  display: flex;
  justify-content: center;
  padding: 32px;
}

/* Project item in sidebar */
.project-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 16px;
  cursor: pointer;
  border-left: 2px solid transparent;
  transition: all var(--transition);
  position: relative;
}

.project-item:hover {
  background: var(--bg-hover);
}

.project-item.active {
  background: var(--gold-glow);
  border-left-color: var(--gold);
}

.project-item__dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-dim);
  flex-shrink: 0;
  transition: background var(--transition);
}

.project-item.active .project-item__dot {
  background: var(--gold);
}

.project-item__info {
  flex: 1;
  min-width: 0;
}

.project-item__name {
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 500;
  color: var(--text);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  line-height: 1.3;
}

.project-item.active .project-item__name {
  color: var(--gold);
}

.project-item__count {
  font-size: 10px;
  color: var(--text-muted);
  margin-top: 2px;
}

.sidebar__footer {
  padding: 12px 16px;
  border-top: 1px solid var(--border);
}

.sidebar__footer-text {
  font-size: 10px;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

/* ============================================
   WELCOME SCREEN
   ============================================ */

.welcome {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  position: relative;
  overflow: hidden;
}

.welcome__inner {
  text-align: center;
  position: relative;
  z-index: 1;
  animation: fadeInUp 0.6s ease both;
}

.welcome__symbol {
  font-size: 48px;
  color: var(--gold-dim);
  margin-bottom: 20px;
  display: block;
}

.welcome__title {
  font-family: var(--font-display);
  font-size: 52px;
  font-weight: 300;
  letter-spacing: 0.05em;
  color: var(--text);
  margin-bottom: 16px;
}

.welcome__subtitle {
  font-size: 12px;
  color: var(--text-muted);
  line-height: 2;
  margin-bottom: 36px;
}

.welcome__bg-text {
  position: absolute;
  bottom: -30px;
  left: 50%;
  transform: translateX(-50%);
  font-family: var(--font-display);
  font-size: 200px;
  font-weight: 600;
  color: rgba(201,168,76,0.03);
  letter-spacing: 0.1em;
  white-space: nowrap;
  pointer-events: none;
  user-select: none;
}

/* ============================================
   PROJECT VIEW
   ============================================ */

.project-view {
  height: 100%;
  display: flex;
  flex-direction: column;
  animation: fadeInUp 0.35s ease both;
}

.project-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  padding: 36px 48px 24px;
  border-bottom: 1px solid var(--border);
  gap: 20px;
}

.project-header__label {
  font-size: 10px;
  color: var(--gold-dim);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  display: block;
  margin-bottom: 8px;
}

.project-header__name {
  font-family: var(--font-display);
  font-size: 38px;
  font-weight: 400;
  color: var(--text);
  line-height: 1.2;
}

.project-header__desc {
  font-size: 12px;
  color: var(--text-muted);
  margin-top: 6px;
  font-style: italic;
}

.project-header__actions {
  display: flex;
  align-items: center;
  gap: 16px;
  flex-shrink: 0;
  padding-top: 8px;
}

.project-header__count {
  font-size: 11px;
  color: var(--text-muted);
  letter-spacing: 0.05em;
}

/* ============================================
   ENTRY FORM SECTION
   ============================================ */

.entry-form-section {
  padding: 28px 48px;
  border-bottom: 1px solid var(--border);
}

.entry-form {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 6px;
  overflow: hidden;
}

.entry-form__header {
  padding: 12px 20px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-raised);
}

.entry-form__label {
  font-size: 10px;
  color: var(--gold-dim);
  letter-spacing: 0.15em;
  text-transform: uppercase;
}

.entry-form__textarea {
  width: 100%;
  background: transparent;
  border: none;
  color: var(--text);
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.8;
  padding: 16px 20px;
  resize: vertical;
  outline: none;
  min-height: 100px;
}

.entry-form__textarea::placeholder {
  color: var(--text-dim);
}

.entry-form__audio {
  padding: 12px 20px;
  border-top: 1px solid var(--border);
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  align-items: center;
}

.audio-controls {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.audio-timer {
  display: flex;
  align-items: center;
  gap: 6px;
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--red);
}

.timer-dot {
  width: 6px;
  height: 6px;
  background: var(--red);
  border-radius: 50%;
  animation: blink 1s step-start infinite;
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

.audio-preview {
  display: flex;
  align-items: center;
  gap: 8px;
}

.audio-preview audio {
  height: 28px;
  max-width: 240px;
  filter: invert(0.85) sepia(0.2);
}

.audio-upload-alt {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-left: auto;
}

.audio-filename {
  font-size: 11px;
  color: var(--text-muted);
  max-width: 180px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.entry-form__actions {
  padding: 12px 20px;
  border-top: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.entry-form__error {
  font-size: 11px;
  color: var(--red);
}

/* ============================================
   ENTRIES LIST
   ============================================ */

.entries-section {
  flex: 1;
  overflow-y: auto;
  padding: 24px 48px 48px;
}

.entries-header {
  margin-bottom: 16px;
}

.entries-header__label {
  font-size: 10px;
  color: var(--gold-dim);
  letter-spacing: 0.15em;
  text-transform: uppercase;
}

.entries-list {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.entries-loading {
  display: flex;
  justify-content: center;
  padding: 40px;
}

.entry-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 4px;
  overflow: hidden;
  animation: fadeInUp 0.3s ease both;
  transition: border-color var(--transition);
}

.entry-card:hover {
  border-color: var(--border-gold);
}

.entry-card__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px;
  background: var(--bg-raised);
  border-bottom: 1px solid var(--border);
}

.entry-card__time {
  font-size: 10px;
  color: var(--text-muted);
  letter-spacing: 0.05em;
}

.entry-card__body {
  padding: 16px;
}

.entry-card__text {
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.8;
  color: var(--text);
  white-space: pre-wrap;
  word-break: break-word;
}

.entry-card__audio {
  padding: 10px 16px 14px;
  border-top: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 10px;
}

.entry-card__audio-label {
  font-size: 10px;
  color: var(--gold-dim);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  flex-shrink: 0;
}

.entry-card__audio audio {
  height: 28px;
  flex: 1;
  filter: invert(0.85) sepia(0.2);
}

.entry-empty {
  text-align: center;
  padding: 64px 32px;
  color: var(--text-muted);
}

.entry-empty__symbol {
  font-size: 32px;
  margin-bottom: 16px;
  opacity: 0.4;
}

.entry-empty__text {
  font-size: 13px;
  font-style: italic;
  line-height: 2;
}

/* ============================================
   BUTTONS
   ============================================ */

.btn {
  cursor: pointer;
  border: none;
  outline: none;
  font-family: var(--font-mono);
  font-size: 11px;
  transition: all var(--transition);
  display: inline-flex;
  align-items: center;
  gap: 6px;
  letter-spacing: 0.05em;
  white-space: nowrap;
}

.btn--new-project {
  width: 28px;
  height: 28px;
  border-radius: 4px;
  background: var(--gold-glow);
  border: 1px solid var(--border-gold);
  color: var(--gold);
  font-size: 18px;
  line-height: 1;
  justify-content: center;
  font-weight: 300;
}

.btn--new-project:hover {
  background: var(--gold);
  color: var(--bg);
}

.btn--cta {
  background: var(--gold);
  color: var(--bg);
  padding: 10px 28px;
  border-radius: 3px;
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.08em;
}

.btn--cta:hover {
  background: var(--amber);
}

.btn--icon {
  width: 32px;
  height: 32px;
  border-radius: 4px;
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  justify-content: center;
}

.btn--icon:hover {
  background: var(--error-bg);
  border-color: var(--red);
  color: var(--red);
}

.btn--record {
  background: var(--bg-raised);
  border: 1px solid var(--border);
  color: var(--text);
  padding: 7px 14px;
  border-radius: 3px;
  font-size: 11px;
}

.btn--record:hover {
  border-color: var(--red);
  color: var(--red);
}

.btn--record.recording {
  background: var(--error-bg);
  border-color: var(--red);
  color: var(--red);
}

.record-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--red);
  display: inline-block;
  transition: opacity var(--transition);
}

.btn--record:not(.recording) .record-dot {
  opacity: 0.4;
}

.btn--record.recording .record-dot {
  animation: blink 0.8s step-start infinite;
}

.btn--upload {
  background: var(--bg-raised);
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 6px 12px;
  border-radius: 3px;
  font-size: 11px;
  cursor: pointer;
}

.btn--upload:hover {
  border-color: var(--border-gold);
  color: var(--gold);
}

.btn--clear-audio {
  background: transparent;
  border: none;
  color: var(--text-muted);
  font-size: 12px;
  width: 22px;
  height: 22px;
  justify-content: center;
}

.btn--clear-audio:hover {
  color: var(--red);
}

.btn--submit {
  background: var(--gold);
  color: var(--bg);
