  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 8px 20px;
  border-radius: 3px;
}

.btn--cancel:hover {
  border-color: var(--text-muted);
  color: var(--text);
}

.btn--save {
  background: var(--gold);
  color: var(--bg);
  padding: 8px 20px;
  border-radius: 3px;
  font-weight: 500;
}

.btn--save:hover {
  background: var(--amber);
}

.btn--danger {
  background: var(--red);
  color: #fff;
  padding: 8px 20px;
  border-radius: 3px;
}

.btn--danger:hover {
  background: #e74c3c;
}

.btn--delete-entry {
  background: transparent;
  border: none;
  color: var(--text-dim);
  font-size: 11px;
  padding: 2px 6px;
  border-radius: 2px;
}

.btn--delete-entry:hover {
  color: var(--red);
  background: var(--error-bg);
}

/* ============================================
   MODAL
   ============================================ */

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.7);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  animation: fadeIn 0.15s ease;
}

.modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 6px;
  width: 100%;
  max-width: 460px;
  margin: 20px;
  animation: slideUp 0.2s ease;
  overflow: hidden;
}

.modal--sm {
  max-width: 360px;
}

.modal__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 18px 24px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-raised);
}

.modal__title {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 400;
  color: var(--text);
}

.modal__close {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 14px;
  cursor: pointer;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 3px;
  transition: all var(--transition);
}

.modal__close:hover {
  background: var(--bg-hover);
  color: var(--text);
}

.modal__body {
  padding: 24px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.modal__footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding: 16px 24px;
  border-top: 1px solid var(--border);
}

.form-label {
  font-size: 11px;
  color: var(--text-muted);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  margin-top: 10px;
  display: block;
}

.form-label:first-child {
  margin-top: 0;
}

.required {
  color: var(--gold-dim);
}

.form-input,
.form-textarea {
  width: 100%;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: 4px;
  color: var(--text);
  font-family: var(--font-mono);
  font-size: 13px;
  padding: 10px 12px;
  outline: none;
  transition: border-color var(--transition);
  resize: vertical;
}

.form-input:focus,
.form-textarea:focus {
  border-color: var(--gold-dim);
}

.form-input::placeholder,
.form-textarea::placeholder {
  color: var(--text-dim);
}

.field-error {
  font-size: 11px;
  color: var(--red);
  min-height: 16px;
  display: block;
}

.confirm-text {
  font-size: 13px;
  color: var(--text-muted);
  line-height: 1.8;
}

/* ============================================
   SPINNER
   ============================================ */

.spinner {
  width: 20px;
  height: 20px;
  border: 2px solid var(--border);
  border-top-color: var(--gold);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ============================================
   TOAST
   ============================================ */

.toast {
  position: fixed;
  bottom: 28px;
  right: 28px;
  background: var(--bg-raised);
  border: 1px solid var(--border-gold);
  color: var(--text);
  font-size: 12px;
  padding: 12px 20px;
  border-radius: 4px;
  transform: translateY(20px);
  opacity: 0;
  transition: all 0.25s ease;
  z-index: 200;
  pointer-events: none;
  max-width: 320px;
}

.toast.show {
  transform: translateY(0);
  opacity: 1;
}

.toast.toast--error {
  border-color: rgba(192,57,43,0.5);
  background: var(--error-bg);
  color: #e07070;
}

/* ============================================
   ANIMATIONS
   ============================================ */

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(16px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes slideUp {
  from { transform: translateY(24px); opacity: 0; }
  to   { transform: translateY(0); opacity: 1; }
}

/* ============================================
   SCROLLBAR
   ============================================ */

.main::-webkit-scrollbar,
.entries-section::-webkit-scrollbar {
  width: 5px;
}
.main::-webkit-scrollbar-track,
.entries-section::-webkit-scrollbar-track {
  background: transparent;
}
.main::-webkit-scrollbar-thumb,
.entries-section::-webkit-scrollbar-thumb {
  background: var(--bg-hover);
  border-radius: 3px;
}

/* ============================================
   RESPONSIVE
   ============================================ */

@media (max-width: 768px) {
  :root { --sidebar-w: 220px; }

  .project-header,
  .entry-form-section,
  .entries-section {
    padding-left: 20px;
    padding-right: 20px;
  }

  .project-header__name {
    font-size: 28px;
  }

  .welcome__title {
    font-size: 36px;
  }

  .welcome__bg-text {
    font-size: 120px;
  }
}
