/**
 * VoiceNote — Main Application Logic
 */

// ============================================
// STATE
// ============================================
const state = {
  projects: [],
  currentProjectId: null,
  mediaRecorder: null,
  audioChunks: [],
  recordedBlob: null,
  uploadedFile: null,
  timerInterval: null,
  timerSeconds: 0,
  confirmCallback: null,
};

// ============================================
// DOM REFS
// ============================================
const $ = (id) => document.getElementById(id);

const els = {
  projectList: $('projectList'),
  projectsLoading: $('projectsLoading'),
  projectCount: $('projectCount'),
  projectSearch: $('projectSearch'),
  welcomeScreen: $('welcomeScreen'),
  projectView: $('projectView'),
  projectName: $('projectName'),
  projectDesc: $('projectDesc'),
  entryCount: $('entryCount'),
  btnDeleteProject: $('btnDeleteProject'),
  // Entry form
  entryText: $('entryText'),
  btnRecord: $('btnRecord'),
  recordLabel: $('recordLabel'),
  audioTimer: $('audioTimer'),
  timerDisplay: $('timerDisplay'),
  audioPreview: $('audioPreview'),
  audioPlayback: $('audioPlayback'),
  btnClearAudio: $('btnClearAudio'),
  audioFileInput: $('audioFileInput'),
  audioFilename: $('audioFilename'),
  entryError: $('entryError'),
  btnSubmitEntry: $('btnSubmitEntry'),
  submitLabel: $('submitLabel'),
  // Entries list
  entriesList: $('entriesList'),
  entriesLoading: $('entriesLoading'),
  // Modals
  modalOverlay: $('modalOverlay'),
  modalTitle: $('modalTitle'),
  inputProjectName: $('inputProjectName'),
  inputProjectDesc: $('inputProjectDesc'),
  nameError: $('nameError'),
  btnSaveProject: $('btnSaveProject'),
  btnCloseModal: $('btnCloseModal'),
  btnCancelModal: $('btnCancelModal'),
  confirmOverlay: $('confirmOverlay'),
  confirmText: $('confirmText'),
  btnConfirmOk: $('btnConfirmOk'),
  btnConfirmCancel: $('btnConfirmCancel'),
  toast: $('toast'),
};

// ============================================
// INIT
// ============================================
document.addEventListener('DOMContentLoaded', () => {
  bindEvents();
  loadProjects();
});

function bindEvents() {
  // New project buttons
  $('btnNewProject').addEventListener('click', openNewProjectModal);
  $('btnWelcomeNew').addEventListener('click', openNewProjectModal);

  // Modal
  els.btnCloseModal.addEventListener('click', closeModal);
  els.btnCancelModal.addEventListener('click', closeModal);
  els.btnSaveProject.addEventListener('click', saveProject);
  els.inputProjectName.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') saveProject();
  });
  els.modalOverlay.addEventListener('click', (e) => {
    if (e.target === els.modalOverlay) closeModal();
  });

  // Confirm modal
  els.btnConfirmCancel.addEventListener('click', closeConfirm);
  els.btnConfirmOk.addEventListener('click', () => {
    closeConfirm();
    if (state.confirmCallback) state.confirmCallback();
  });
  els.confirmOverlay.addEventListener('click', (e) => {
    if (e.target === els.confirmOverlay) closeConfirm();
  });

  // Delete project
  els.btnDeleteProject.addEventListener('click', () => {
    const project = state.projects.find(p => p.id === state.currentProjectId);
    if (!project) return;
    showConfirm(
      `Xóa project "<strong>${escapeHtml(project.name)}</strong>"? Tất cả ghi chú sẽ bị xóa vĩnh viễn.`,
      async () => {
        await deleteProject(project.id);
      }
    );
  });

  // Entry form
  els.btnRecord.addEventListener('click', toggleRecording);
  els.btnClearAudio.addEventListener('click', clearAudio);
  els.audioFileInput.addEventListener('change', handleFileUpload);
  els.btnSubmitEntry.addEventListener('click', submitEntry);

  // Search
  els.projectSearch.addEventListener('input', renderProjectList);
}

// ============================================
// PROJECTS
// ============================================
async function loadProjects() {
  els.projectsLoading.style.display = 'flex';
  try {
    state.projects = await api.get('/api/projects');
    renderProjectList();
  } catch (err) {
    showToast('Lỗi tải projects: ' + err.message, 'error');
  } finally {
    els.projectsLoading.style.display = 'none';
  }
}

function renderProjectList() {
  const query = els.projectSearch.value.toLowerCase().trim();
  const filtered = query
    ? state.projects.filter(p => p.name.toLowerCase().includes(query) || (p.description || '').toLowerCase().includes(query))
    : state.projects;

  els.projectCount.textContent = `${state.projects.length} project${state.projects.length !== 1 ? 's' : ''}`;

  // Clear existing items (keep loading el)
  els.projectList.querySelectorAll('.project-item').forEach(el => el.remove());

  if (filtered.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'entry-empty';
    empty.style.padding = '24px 16px';
    empty.innerHTML = `<p class="entry-empty__text">${query ? 'Không tìm thấy.' : 'Chưa có project nào.'}</p>`;
    // remove old empty
    els.projectList.querySelectorAll('.entry-empty').forEach(e => e.remove());
    els.projectList.appendChild(empty);
    return;
  }

  els.projectList.querySelectorAll('.entry-empty').forEach(e => e.remove());

  filtered.forEach(project => {
    const item = document.createElement('div');
    item.className = 'project-item' + (project.id === state.currentProjectId ? ' active' : '');
    item.dataset.id = project.id;
    item.innerHTML = `
      <span class="project-item__dot"></span>
      <div class="project-item__info">
        <div class="project-item__name">${escapeHtml(project.name)}</div>
        <div class="project-item__count">${project.entry_count} ghi chú</div>
      </div>
    `;
    item.addEventListener('click', () => selectProject(project.id));
    els.projectList.appendChild(item);
  });
}

async function selectProject(id) {
  state.currentProjectId = id;
  renderProjectList();

  const project = state.projects.find(p => p.id === id);
  if (!project) return;

  els.welcomeScreen.style.display = 'none';
  els.projectView.style.display = 'flex';

  els.projectName.textContent = project.name;
  els.projectDesc.textContent = project.description || '';
  els.entryCount.textContent = `${project.entry_count} entries`;

  // Reset form
  resetEntryForm();

  // Load entries
  await loadEntries(id);
}

async function deleteProject(id) {
  try {
    await api.delete(`/api/projects/${id}`);
    state.projects = state.projects.filter(p => p.id !== id);
    state.currentProjectId = null;
    renderProjectList();
    els.projectView.style.display = 'none';
    els.welcomeScreen.style.display = 'flex';
    showToast('Project đã được xóa.');
  } catch (err) {
    showToast('Lỗi xóa project: ' + err.message, 'error');
  }
}

// ============================================
// MODAL: NEW PROJECT
// ============================================
function openNewProjectModal() {
  els.inputProjectName.value = '';
  els.inputProjectDesc.value = '';
  els.nameError.textContent = '';
  els.modalTitle.textContent = 'Tạo Project Mới';
  els.modalOverlay.style.display = 'flex';
  setTimeout(() => els.inputProjectName.focus(), 100);
}

function closeModal() {
  els.modalOverlay.style.display = 'none';
}

async function saveProject() {
  const name = els.inputProjectName.value.trim();
  if (!name) {
    els.nameError.textContent = 'Tên project không được để trống.';
    els.inputProjectName.focus();
    return;
  }
  els.nameError.textContent = '';
  els.btnSaveProject.disabled = true;
  els.btnSaveProject.textContent = '...';

  try {
    const project = await api.post('/api/projects', {
      name,
      description: els.inputProjectDesc.value.trim() || null,
    });
    state.projects.unshift(project);
    renderProjectList();
    closeModal();
    selectProject(project.id);
    showToast(`Project "${project.name}" đã được tạo.`);
  } catch (err) {
    showToast('Lỗi tạo project: ' + err.message, 'error');
  } finally {
    els.btnSaveProject.disabled = false;
    els.btnSaveProject.textContent = 'Tạo';
  }
}

// ============================================
// CONFIRM MODAL
// ============================================
function showConfirm(htmlMessage, callback) {
  els.confirmText.innerHTML = htmlMessage;
  state.confirmCallback = callback;
  els.confirmOverlay.style.display = 'flex';
}

function closeConfirm() {
  els.confirmOverlay.style.display = 'none';
  state.confirmCallback = null;
}

// ============================================
// ENTRIES
// ============================================
async function loadEntries(projectId) {
  els.entriesLoading.style.display = 'flex';
  // Clear old entries
  els.entriesList.querySelectorAll('.entry-card, .entry-empty').forEach(e => e.remove());

  try {
    const entries = await api.get(`/api/projects/${projectId}/entries`);
    renderEntries(entries);
  } catch (err) {
    showToast('Lỗi tải ghi chú: ' + err.message, 'error');
  } finally {
    els.entriesLoading.style.display = 'none';
  }
}

function renderEntries(entries) {
  els.entriesList.querySelectorAll('.entry-card, .entry-empty').forEach(e => e.remove());

  if (entries.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'entry-empty';
    empty.innerHTML = `
      <div class="entry-empty__symbol">◈</div>
      <p class="entry-empty__text">Chưa có ghi chú nào trong project này.<br/>Thêm ghi chú đầu tiên ở phía trên.</p>
    `;
    els.entriesList.appendChild(empty);
    return;
  }

  entries.forEach((entry, i) => {
    const card = createEntryCard(entry, i);
    els.entriesList.appendChild(card);
  });
}

function createEntryCard(entry, index) {
  const card = document.createElement('div');
  card.className = 'entry-card';
  card.dataset.id = entry.id;
  card.style.animationDelay = `${index * 40}ms`;

  const timeStr = formatDateTime(entry.created_at);

  let audioHtml = '';
  if (entry.audio_url) {
    audioHtml = `
      <div class="entry-card__audio">
        <span class="entry-card__audio-label">◈ audio</span>
        <audio src="${escapeHtml(entry.audio_url)}" controls></audio>
      </div>
    `;
  }

  card.innerHTML = `
    <div class="entry-card__header">
      <span class="entry-card__time">${timeStr}</span>
      <button class="btn btn--delete-entry" data-id="${entry.id}" title="Xóa ghi chú">✕</button>
    </div>
    <div class="entry-card__body">
      <p class="entry-card__text">${escapeHtml(entry.text_content)}</p>
    </div>
    ${audioHtml}
  `;

  card.querySelector('.btn--delete-entry').addEventListener('click', (e) => {
    e.stopPropagation();
    showConfirm('Xóa ghi chú này?', async () => {
      await deleteEntry(entry.id);
    });
  });

  return card;
}

async function deleteEntry(entryId) {
  try {
    await api.delete(`/api/projects/entries/${entryId}`);
    // Remove from DOM
    const card = els.entriesList.querySelector(`[data-id="${entryId}"]`);
    if (card) card.remove();

    // Update count
    const project = state.projects.find(p => p.id === state.currentProjectId);
    if (project) {
      project.entry_count = Math.max(0, project.entry_count - 1);
      els.entryCount.textContent = `${project.entry_count} entries`;
      renderProjectList();
    }

    // Show empty if needed
    if (els.entriesList.querySelectorAll('.entry-card').length === 0) {
      renderEntries([]);
    }

    showToast('Ghi chú đã được xóa.');
  } catch (err) {
    showToast('Lỗi xóa ghi chú: ' + err.message, 'error');
  }
}

// ============================================
// ENTRY FORM
// ============================================
function resetEntryForm() {
  els.entryText.value = '';
  els.entryError.textContent = '';
  clearAudio();
}

async function submitEntry() {
  const text = els.entryText.value.trim();
  if (!text) {
    els.entryError.textContent = 'Vui lòng nhập nội dung ghi chú.';
    els.entryText.focus();
    return;
  }
  els.entryError.textContent = '';

  const formData = new FormData();
  formData.append('text_content', text);

  // Attach audio
  if (state.recordedBlob) {
    formData.append('audio', state.recordedBlob, 'recording.webm');
  } else if (state.uploadedFile) {
    formData.append('audio', state.uploadedFile, state.uploadedFile.name);
  }

  els.btnSubmitEntry.disabled = true;
  els.submitLabel.textContent = 'Đang lưu...';

  try {
    const entry = await api.uploadForm(`/api/projects/${state.currentProjectId}/entries`, formData);
    // Prepend to list
    const existingEmpty = els.entriesList.querySelector('.entry-empty');
    if (existingEmpty) existingEmpty.remove();

    const card = createEntryCard(entry, 0);
    els.entriesList.insertBefore(card, els.entriesList.firstChild);

    // Update count
    const project = state.projects.find(p => p.id === state.currentProjectId);
    if (project) {
      project.entry_count += 1;
      els.entryCount.textContent = `${project.entry_count} entries`;
      renderProjectList();
    }

    resetEntryForm();
    showToast('Ghi chú đã được lưu!');
  } catch (err) {
    els.entryError.textContent = 'Lỗi: ' + err.message;
    showToast('Lỗi lưu ghi chú: ' + err.message, 'error');
  } finally {
    els.btnSubmitEntry.disabled = false;
    els.submitLabel.textContent = 'Lưu ghi chú';
  }
}

// ============================================
// AUDIO RECORDING
// ============================================
async function toggleRecording() {
  if (state.mediaRecorder && state.mediaRecorder.state === 'recording') {
    stopRecording();
  } else {
    await startRecording();
  }
}

async function startRecording() {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    state.audioChunks = [];
    state.mediaRecorder = new MediaRecorder(stream);

    state.mediaRecorder.ondataavailable = (e) => {
      if (e.data.size > 0) state.audioChunks.push(e.data);
    };

    state.mediaRecorder.onstop = () => {
      const blob = new Blob(state.audioChunks, { type: 'audio/webm' });
      state.recordedBlob = blob;
      state.uploadedFile = null;
      els.audioFilename.textContent = '';

      const url = URL.createObjectURL(blob);
      els.audioPlayback.src = url;
      els.audioPreview.style.display = 'flex';
      els.audioTimer.style.display = 'none';

      // Stop tracks
      stream.getTracks().forEach(t => t.stop());
      clearInterval(state.timerInterval);
    };

    state.mediaRecorder.start();

    // UI
    els.btnRecord.classList.add('recording');
    els.recordLabel.textContent = 'Dừng';
    els.audioPreview.style.display = 'none';
    els.audioTimer.style.display = 'flex';
    state.timerSeconds = 0;
    els.timerDisplay.textContent = '00:00';

    state.timerInterval = setInterval(() => {
      state.timerSeconds++;
      const m = String(Math.floor(state.timerSeconds / 60)).padStart(2, '0');
      const s = String(state.timerSeconds % 60).padStart(2, '0');
      els.timerDisplay.textContent = `${m}:${s}`;
    }, 1000);

