  } catch (err) {
    showToast('Lỗi tải projects: ' + err.message, 'error');
  } finally {
    els.projectsLoading.style.display = 'none';
  }
}

function renderProjectList() {
  const query = els.projectSearch.value.toLowerCase().trim();
  const filtered = query
    ? state.projects.filter(p => p.name.toLowerCase().includes(query) || (p.description || '').toLowerCase().includes(query))
    : state.projects;

  els.projectCount.textContent = `${state.projects.length} project${state.projects.length !== 1 ? 's' : ''}`;

  // Clear existing items (keep loading el)
  els.projectList.querySelectorAll('.project-item').forEach(el => el.remove());

  if (filtered.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'entry-empty';
    empty.style.padding = '24px 16px';
    empty.innerHTML = `<p class="entry-empty__text">${query ? 'Không tìm thấy.' : 'Chưa có project nào.'}</p>`;
    // remove old empty
    els.projectList.querySelectorAll('.entry-empty').forEach(e => e.remove());
    els.projectList.appendChild(empty);
    return;
  }

  els.projectList.querySelectorAll('.entry-empty').forEach(e => e.remove());

  filtered.forEach(project => {
    const item = document.createElement('div');
    item.className = 'project-item' + (project.id === state.currentProjectId ? ' active' : '');
    item.dataset.id = project.id;
    item.innerHTML = `
      <span class="project-item__dot"></span>
      <div class="project-item__info">
        <div class="project-item__name">${escapeHtml(project.name)}</div>
        <div class="project-item__count">${project.entry_count} ghi chú</div>
      </div>
    `;
    item.addEventListener('click', () => selectProject(project.id));
    els.projectList.appendChild(item);
  });
}

async function selectProject(id) {
  state.currentProjectId = id;
  renderProjectList();

  const project = state.projects.find(p => p.id === id);
  if (!project) return;

  els.welcomeScreen.style.display = 'none';
  els.projectView.style.display = 'flex';

  els.projectName.textContent = project.name;
  els.projectDesc.textContent = project.description || '';
