    return;
  }

  entries.forEach((entry, i) => {
    const card = createEntryCard(entry, i);
    els.entriesList.appendChild(card);
  });
}

function createEntryCard(entry, index) {
  const card = document.createElement('div');
  card.className = 'entry-card';
  card.dataset.id = entry.id;
  card.style.animationDelay = `${index * 40}ms`;

  const timeStr = formatDateTime(entry.created_at);

  let audioHtml = '';
  if (entry.audio_url) {
    audioHtml = `
      <div class="entry-card__audio">
        <span class="entry-card__audio-label">◈ audio</span>
        <audio src="${escapeHtml(entry.audio_url)}" controls></audio>
