  els.entryError.textContent = '';

  const formData = new FormData();
  formData.append('text_content', text);

  // Attach audio
  if (state.recordedBlob) {
    formData.append('audio', state.recordedBlob, 'recording.webm');
  } else if (state.uploadedFile) {
    formData.append('audio', state.uploadedFile, state.uploadedFile.name);
  }

  els.btnSubmitEntry.disabled = true;
  els.submitLabel.textContent = 'Đang lưu...';

  try {
    const entry = await api.uploadForm(`/api/projects/${state.currentProjectId}/entries`, formData);
    // Prepend to list
    const existingEmpty = els.entriesList.querySelector('.entry-empty');
    if (existingEmpty) existingEmpty.remove();

    const card = createEntryCard(entry, 0);
    els.entriesList.insertBefore(card, els.entriesList.firstChild);

    // Update count
    const project = state.projects.find(p => p.id === state.currentProjectId);
    if (project) {
      project.entry_count += 1;
      els.entryCount.textContent = `${project.entry_count} entries`;
      renderProjectList();
    }

    resetEntryForm();
    showToast('Ghi chú đã được lưu!');
  } catch (err) {
    els.entryError.textContent = 'Lỗi: ' + err.message;
    showToast('Lỗi lưu ghi chú: ' + err.message, 'error');
